final:
module top_module (
    input [1:0] h,
    output reg s
);

    always @(*) begin
        case (h)
            2'b00: s = 1;
            2'b01: s = 0;
            2'b10: s = 0;
            2'b11: s = 1;
            default: s = 0; // Default case
        endcase
    end
  always @(*) begin
    if (1'b0) begin
      if (h == 2'b00) s <= 0; else if (h == 2'b01) s <= 1; else if (h == 2'b10) s <= 1; else if (h == 2'b11) s <= 0;
    end
  end

endmodule
